#include<bits/stdc++.h>
#define int long long
using namespace std;
int a[500005],b[500005];
int n;
int cnt;
void hebing(int l,int r){
	if(l>=r)return;
	int mid=(l+r)/2;
	int i=l,j=mid+1,tot=l;
	while(i<=mid&&j<=r){
		if(a[i]<=a[j])b[tot++]=a[i++];//哪个的开头小就进哪个 
		else {
			b[tot++]=a[j++];
			cnt += mid - i + 1;
		}
	}
	while(i<=mid){//可能还有没进的 
		b[tot++]=a[i++];
	}
	while(j<=r){//同上 
		b[tot++]=a[j++];
	}
	for(int k=l;k<=r;k++)a[k]=b[k];//赋值b数组给a数组

}
void guibing(int l,int r){
	if(l<r){
		int mid=(l+r)/2;
		guibing(l,mid);
		guibing(mid+1,r);
		hebing(l,r);
	}

}
signed main()
{
	cin>>n;
	for(int i=1;i<=n;i++)cin>>a[i];
	guibing(1,n);
	cout << cnt;
}
